    private static void applyGlobalSkillTuning() {
        multiplySkillRanges(SKILL_RANGE, SKILL_RANGE_MULTIPLIER);
        multiplySkillRanges(RANGE_SKILL_AEO, SKILL_RANGE_MULTIPLIER);
        reduceSkillCooldowns(SKILL_COOLDOWN, SKILL_COOLDOWN_DIVISOR);
    }

    private static void multiplySkillRanges(short[][] ranges, int multiplier) {
        for (int i = 0; i < ranges.length; i++) {
            for (int j = 0; j < ranges[i].length; j++) {
                ranges[i][j] = multiplyShort(ranges[i][j], multiplier);
            }
        }
    }

    private static void multiplySkillRanges(short[][][] ranges, int multiplier) {
        for (int i = 0; i < ranges.length; i++) {
            for (int j = 0; j < ranges[i].length; j++) {
                for (int k = 0; k < ranges[i][j].length; k++) {
                    ranges[i][j][k] = multiplyShort(ranges[i][j][k], multiplier);
                }
            }
        }
    }

    private static void reduceSkillCooldowns(short[][][] cooldowns, int divisor) {
        for (int i = 0; i < cooldowns.length; i++) {
            for (int j = 0; j < cooldowns[i].length; j++) {
                for (int k = 0; k < cooldowns[i][j].length; k++) {
                    cooldowns[i][j][k] = divideCooldown(cooldowns[i][j][k], divisor);
                }
            }
        }
    }

    private static short multiplyShort(short value, int multiplier) {
        if (value <= 0) {
            return value;
        }
        return (short) Math.min(Short.MAX_VALUE, value * multiplier);
    }

    private static short divideCooldown(short value, int divisor) {
        if (value <= 1) {
            return value;
        }
        return (short) Math.max(1, value / divisor);
    }

